            Self::LimitExceeded => "Limit Exceeded",
            Self::NoModManager => "No Mod Manager",
            Self::UnknownGameVersion => "Unknown Game Version",
            Self::Custom(label) => label.as_str(),
        }
    }

    fn group_rank(&self) -> usize {
