    #[test]
    fn scanner_autofix_service_rejects_missing_target_and_missing_confirmation_before_execute() {
        let filesystem = FakeFilesystem::default().with_file("Data/junk.txt");
        let (pathless_operation, _pathless_preconditions, pathless_execute_calls) =
            FakeOperation::new(FakePrecondition::Pass, FakeExecution::Succeed);
        let pathless_service = service_with_operation(
            &filesystem,
            support(AutoFixOperationKey::DeleteFile).with_required_target_path(),
            pathless_operation,
        );
        let pathless_snapshot = snapshot(pathless_result(ScannerSolutionKind::DeleteFile));

        let AutoFixPlanResult::Rejected(target_rejection) =
            pathless_service.plan(&pathless_snapshot, plan_request(&pathless_snapshot))
        else {
            panic!("target-required operation must reject pathless results");
        };
        assert_eq!(target_rejection.reason, AutoFixRejectionReason::MissingTargetPath);
        assert_eq!(pathless_execute_calls.load(Ordering::SeqCst), 0);

        let (confirm_operation, _confirm_preconditions, confirm_execute_calls) =
            FakeOperation::new(FakePrecondition::Pass, FakeExecution::Succeed);
        let confirm_service = service_with_operation(
            &filesystem,
            support(AutoFixOperationKey::DeleteFile)
                .with_required_target_path()
                .with_confirmation("Delete this fake file?"),
            confirm_operation,
        );
        let confirm_snapshot = snapshot(path_result(ScannerSolutionKind::DeleteFile, "Data/junk.txt"));
        let AutoFixPlanResult::Planned(preview) =
            confirm_service.plan(&confirm_snapshot, plan_request(&confirm_snapshot))
        else {
            panic!("target-backed operation should plan before confirmation");
        };
        let request_without_confirmation = executable_request(preview.clone());

        let AutoFixServiceResult::Rejected(confirmation_rejection) =
            confirm_service.execute(&confirm_snapshot, 0, request_without_confirmation)
        else {
            panic!("missing confirmation must reject before execute");
        };
        assert_eq!(
            confirmation_rejection.reason,
            AutoFixRejectionReason::ConfirmationRequired
        );
        assert_eq!(confirm_execute_calls.load(Ordering::SeqCst), 0);

        let mut declined_request = executable_request(preview.clone());
        declined_request.confirmation = Some(confirmation_for(&preview, false));
        let AutoFixServiceResult::Rejected(declined_rejection) =
            confirm_service.execute(&confirm_snapshot, 0, declined_request)
        else {
            panic!("declined confirmation must reject before execute");
        };
        assert_eq!(
            declined_rejection.reason,
            AutoFixRejectionReason::ConfirmationDeclined
        );
        assert_eq!(confirm_execute_calls.load(Ordering::SeqCst), 0);
    }

    #[test]
    fn scanner_autofix_service_rejects_failed_precondition_before_execute() {
        let filesystem = FakeFilesystem::default();
        let (operation, precondition_calls, execute_calls) = FakeOperation::new(
            FakePrecondition::RequireExistingTarget,
            FakeExecution::Succeed,
        );
        let service = service_with_operation(
            &filesystem,
            support(AutoFixOperationKey::DeleteFile).with_required_target_path(),
            operation,
        );
        let snapshot = snapshot(path_result(ScannerSolutionKind::DeleteFile, "Data/missing.txt"));
        let AutoFixPlanResult::Planned(preview) = service.plan(&snapshot, plan_request(&snapshot)) else {
            panic!("precondition checks happen during execute, not plan");
        };
        let mut request = executable_request(preview.clone());
        request.confirmation = None;

        let AutoFixServiceResult::Rejected(rejection) = service.execute(&snapshot, 0, request) else {
            panic!("failed precondition must reject before execute");
        };

        assert_eq!(rejection.reason, AutoFixRejectionReason::ValidationFailed);
        assert_eq!(rejection.safe_message, SAFE_VALIDATION_FAILED_MESSAGE);
        assert_eq!(rejection.operation_key, Some(AutoFixOperationKey::DeleteFile));
        assert!(
            rejection
                .diagnostic
                .as_deref()
                .is_some_and(|diagnostic| diagnostic.contains("NotFound"))
        );
