            Some(request.operation_key),
            Some(current_identity.clone()),
            None,
            Some("confirmation was declined".to_owned()),
        ));
    }
    if confirmation.requires_pre_mutation_revalidation
        && !request.revalidation.required_before_mutation
    {
        return Err(reject(
